import React, { useState } from "react";
import API from "../api";

const StressAnalysis = () => {
    const [text, setText] = useState("");
    const [response, setResponse] = useState(null);

    const submitStress = async () => {
        const res = await API.post("stress/", { user: 1, text_input: text, stress_level: "Pending" });
        setResponse(res.data);
        setText("");
    };

    return (
        <div>
            <h2>Stress/Anxiety Checker</h2>
            <textarea value={text} onChange={(e) => setText(e.target.value)} placeholder="Describe your feelings" />
            <button onClick={submitStress}>Submit</button>
            {response && <p>Submitted! ID: {response.id}</p>}
        </div>
    );
};

export default StressAnalysis;
